import json
import boto3
import logging
from botocore.exceptions import ClientError

logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    s3_client = boto3.client('s3')
    sns_client = boto3.client('sns')
    
    try:
        for record in event['Records']:
            bucket_name = record['s3']['bucket']['name']
            object_key = record['s3']['object']['key']
            
            response = s3_client.get_object(Bucket=bucket_name, Key=object_key)
            file_content = response['Body'].read()

            # Process the file_content as needed
            processed_content = file_content  # Placeholder for actual image processing
            
            # Write results back to S3
            result_key = "processed-" + object_key
            s3_client.put_object(
                Bucket=bucket_name,
                Key=result_key,
                Body=processed_content
            )
            
            # Send notification via SNS
            sns_client.publish(
                TopicArn='arn:aws:sns:us-east-1:123456789012:MyTopic',
                Message=f"File processed: {object_key}, stored: {result_key}"
            )
            
            logger.info(f"Processed {object_key} and uploaded results to {result_key}")
            
    except ClientError as e:
        logger.error(f"Error processing file: {e}")
        raise e

    return {
        'statusCode': 200,
        'body': json.dumps('Image processing complete.')
    }